// BeadClose is the resolver for the beadClose field.
func (r *mutationResolver) BeadClose(ctx context.Context, id string, reason *string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	store := r.beadStore(ctx)
	if err := store.Close(ctx, id); err != nil {
		return nil, err
	}
	if reason != nil && strings.TrimSpace(*reason) != "" {
		_ = store.AppendEvent(id, bead.BeadEvent{
			Kind:    "summary",
			Summary: "closed: " + strings.TrimSpace(*reason),
		})
	}
	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// WorkerDispatch is the resolver for the workerDispatch field.
func (r *mutationResolver) WorkerDispatch(ctx context.Context, kind string, projectID string, args *string) (*WorkerDispatchResult, error) {
	switch kind {
	case "work":
		if r.Actions == nil {
			return nil, fmt.Errorf("work worker dispatcher is not configured")
		}
		return r.Actions.DispatchWorker(ctx, kind, r.projectRoot(ctx, projectID), args)
	case "realign-specs", "run-checks":
		return &WorkerDispatchResult{
			ID:    "queued-worker-" + slug(kind),
			State: queuedPlaceholderState,
			Kind:  kind,
		}, nil
	default:
		return nil, fmt.Errorf("unsupported worker kind %q", kind)
	}
}

// StartWorker is the resolver for the startWorker field.
//
// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
// project's .ddx/config.yaml drives default harness/profile/effort/label
// values when the GraphQL input leaves them unset. Input fields are layered
// onto config as CLIOverrides — when present they win over the on-disk
// values. The resolved values are forwarded to ActionDispatcher (and ultimately
// to runWorker, which re-loads config to drive the loop's durable knobs like
// review_max_retries / no_progress_cooldown / heartbeat_interval). This
// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
// shadowed the on-disk config.
func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
	if r.Actions == nil {
		return nil, fmt.Errorf("work worker dispatcher is not configured")
	}
	projectRoot := r.projectRoot(ctx, input.ProjectID)

	overrides := config.CLIOverrides{}
	if input.Harness != nil {
		overrides.Harness = strings.TrimSpace(*input.Harness)
	}
	if input.Profile != nil {
		overrides.Profile = strings.TrimSpace(*input.Profile)
	}
	if input.Effort != nil {
		overrides.Effort = strings.TrimSpace(*input.Effort)
	}
	rcfg, _ := config.LoadAndResolve(projectRoot, overrides)

	args := map[string]string{}
	if v := rcfg.Harness(); v != "" {
		args["harness"] = v
	}
	profile := rcfg.Profile()
	if profile == "" {
		profile = "smart"
	}
	args["profile"] = profile
	effort := rcfg.Effort()
	if effort == "" {
		effort = "medium"
	}
	args["effort"] = effort
	if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
		args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
	}
	mode := "watch"
	if input.Mode != nil && strings.TrimSpace(*input.Mode) != "" {
		mode = strings.TrimSpace(*input.Mode)
	}
	args["mode"] = mode
	if input.IdleInterval != nil && strings.TrimSpace(*input.IdleInterval) != "" {
		args["idle_interval"] = strings.TrimSpace(*input.IdleInterval)
	} else if mode == "watch" {
		args["idle_interval"] = "30s"
	}
	raw, err := json.Marshal(args)
	if err != nil {
		return nil, err
	}
	rawArgs := string(raw)
	return r.Actions.DispatchWorker(ctx, "work", projectRoot, &rawArgs)
}

